# Generated by Codex for Pyomo DoE benchmarking.
"""Build per-case Greybox/Central ratio bar plots from benchmark run metrics.

Purpose:
Create one horizontal ratio chart per central/greybox script pair using the
`runs_all_12metrics_from_logs.csv` benchmark table, and save companion summary
CSV files containing metric-level mean/std ratio statistics.

Environment used:
Designed to run in the project Python environment with pandas, numpy, and
matplotlib available.

Output structure:
For each detected case (base script name), writes:
- ratio_12metrics_<case_name>.png
- ratio_12metrics_<case_name>_stats.csv
under the selected output directory (default: data_greybox_benchmarking).

Assumptions:
- Input CSV contains at least:
  mode, script_name, run_index, status, return_code, and the required metrics.
- Central scripts are named with suffixes like `_central.py` or
  `_central_prior.py`.
- Greybox scripts are named with suffixes `_central_greybox.py` or
  `_greybox.py`.
- Runs are paired by `(base_case_name, run_index)`.
"""

from __future__ import annotations

import argparse
import re
from pathlib import Path
from typing import Iterable

import matplotlib.pyplot as plt
import numpy as np
import pandas as pd

INPUT_CSV = Path("data_greybox_benchmarking/runs_all_12metrics_from_logs.csv")
OUTPUT_DIR = Path("data_greybox_benchmarking")

METRICS = [
    ("build_time_s", "Build Time"),
    ("init_time_s", "Initialization Time"),
    ("solve_time_s", "Solve Time"),
    ("wall_time_s", "Wall Time"),
    ("solve_time_per_iter", "Solve Time per Iteration"),
    ("ipopt_iterations", "Iteration Count"),
    ("ipopt_cpu_no_eval_s", "CPU Time (without feval)"),
    ("ipopt_cpu_nlp_eval_s", "CPU Time (feval)"),
    ("ipopt_obj_eval", "Objective Evaluations"),
    ("ipopt_grad_eval", "Gradient Evaluations"),
    ("ipopt_eq_con_eval", "Constraint Evaluations"),
    ("ipopt_eq_jac_eval", "Jacobian Evaluations"),
    ("ipopt_hess_eval", "Hessian Evaluations"),
]


def parse_args() -> argparse.Namespace:
    """Parse command-line arguments for input and output locations."""
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "--input-csv",
        type=Path,
        default=INPUT_CSV,
        help=f"Input metrics CSV (default: {INPUT_CSV})",
    )
    parser.add_argument(
        "--output-dir",
        type=Path,
        default=OUTPUT_DIR,
        help=f"Output directory (default: {OUTPUT_DIR})",
    )
    return parser.parse_args()


def base_case_name(script_name: str) -> str:
    """Normalize script filename to a common base case for central/greybox pairing."""
    name = Path(str(script_name)).name
    name = re.sub(r"\.py$", "", name)
    name = re.sub(r"_central_prior$", "", name)
    name = re.sub(r"_central_greybox$", "", name)
    name = re.sub(r"_greybox$", "", name)
    name = re.sub(r"_central$", "", name)
    return name


def safe_divide(numerator: pd.Series, denominator: pd.Series) -> pd.Series:
    """Return elementwise division with non-finite results converted to NaN."""
    num = pd.to_numeric(numerator, errors="coerce")
    den = pd.to_numeric(denominator, errors="coerce")
    with np.errstate(divide="ignore", invalid="ignore"):
        out = num / den
    out[~np.isfinite(out)] = np.nan
    return out


def required_columns() -> list[str]:
    """List all columns required from the input benchmark CSV."""
    return [
        "mode",
        "script_name",
        "run_index",
        "status",
        "return_code",
    ] + [m for m, _ in METRICS if m != "solve_time_per_iter"]


def validate_input(df: pd.DataFrame) -> None:
    """Validate that input dataframe has all fields needed for ratio calculations."""
    missing = [c for c in required_columns() if c not in df.columns]
    if missing:
        raise SystemExit(f"Missing required columns: {missing}")


def make_paired_table(df: pd.DataFrame) -> pd.DataFrame:
    """Filter success rows and pair central/greybox records by case and run index."""
    valid = df[(df["status"] == "ok") & (pd.to_numeric(df["return_code"], errors="coerce") == 0)].copy()
    valid["run_index"] = pd.to_numeric(valid["run_index"], errors="coerce").astype("Int64")
    valid["base_case"] = valid["script_name"].map(base_case_name)
    valid["solve_time_per_iter"] = safe_divide(valid["solve_time_s"], valid["ipopt_iterations"])

    c = valid[valid["mode"].str.lower() == "central"].copy()
    g = valid[valid["mode"].str.lower() == "greybox"].copy()

    value_cols = [m for m, _ in METRICS]
    merge_cols = ["base_case", "run_index"]
    paired = pd.merge(
        g[merge_cols + value_cols + ["script_name"]],
        c[merge_cols + value_cols + ["script_name"]],
        on=merge_cols,
        how="inner",
        suffixes=("_greybox", "_central"),
    )
    return paired.sort_values(["base_case", "run_index"], kind="stable").reset_index(drop=True)


def compute_metric_stats(paired_case: pd.DataFrame) -> pd.DataFrame:
    """Compute per-metric ratio count/mean/std for one paired case dataframe."""
    rows: list[dict[str, object]] = []
    for metric_key, metric_label in METRICS:
        ratios = safe_divide(
            paired_case[f"{metric_key}_greybox"],
            paired_case[f"{metric_key}_central"],
        )
        valid = ratios[np.isfinite(ratios)]
        rows.append(
            {
                "metric_key": metric_key,
                "metric_label": metric_label,
                "N": int(valid.shape[0]),
                "mean_ratio": float(valid.mean()) if not valid.empty else np.nan,
                "std_ratio": float(valid.std(ddof=0)) if not valid.empty else np.nan,
            }
        )
    return pd.DataFrame(rows)


def plot_case(stats_df: pd.DataFrame, out_png: Path) -> None:
    """Render one ratio bar plot with horizontal error bars and reference lines."""
    labels = stats_df["metric_label"].tolist()
    means = stats_df["mean_ratio"].to_numpy(dtype=float)
    stds = stats_df["std_ratio"].to_numpy(dtype=float)
    y_pos = np.arange(len(labels))
    colors = plt.cm.tab20(np.linspace(0.0, 1.0, len(labels)))

    fig = plt.figure(figsize=(14, 8))
    plt.barh(
        y_pos,
        means,
        xerr=stds,
        alpha=0.7,
        color=colors,
        error_kw=dict(elinewidth=3, capsize=6, capthick=3, ecolor="black"),
    )
    plt.axvline(1.0, color="black", linewidth=3, linestyle="-")
    plt.yticks(y_pos, labels, fontsize=14)
    plt.xticks(fontsize=14)
    plt.xlabel(
        r"$\mathrm{Ratio}\left(\frac{\mathrm{Greybox}}{\mathrm{Central}}\right)$",
        fontsize=18,
    )
    plt.ylabel("")
    plt.grid(True, axis="x", linestyle="--", linewidth=0.6)
    plt.gca().invert_yaxis()
    fig.tight_layout()
    fig.savefig(out_png, dpi=300)
    plt.close(fig)


def emit_case_outputs(case_name: str, paired_case: pd.DataFrame, output_dir: Path) -> tuple[Path, Path]:
    """Write stats CSV and plot PNG for one case and return output paths."""
    stats_df = compute_metric_stats(paired_case)
    out_stats = output_dir / f"ratio_12metrics_{case_name}_stats.csv"
    out_png = output_dir / f"ratio_12metrics_{case_name}.png"
    stats_df.to_csv(out_stats, index=False)
    plot_case(stats_df, out_png)
    return out_png, out_stats


def log_incomplete_cases(case_name: str, stats_df: pd.DataFrame, expected_n: int = 10) -> None:
    """Print any metrics with fewer than expected paired ratios."""
    under = stats_df[stats_df["N"] < expected_n]
    if under.empty:
        return
    pairs = ", ".join(f"{r.metric_key}:N={int(r.N)}" for r in under.itertuples(index=False))
    print(f"[{case_name}] paired runs < {expected_n} for: {pairs}")


def iter_cases(paired: pd.DataFrame) -> Iterable[tuple[str, pd.DataFrame]]:
    """Yield (case_name, paired_case_dataframe) in deterministic case-name order."""
    for case_name in sorted(paired["base_case"].dropna().unique().tolist()):
        yield case_name, paired[paired["base_case"] == case_name].copy()


def main() -> None:
    """Load input CSV, compute per-case ratios, and write plot/stat artifacts."""
    args = parse_args()
    if not args.input_csv.exists():
        raise SystemExit(f"Input CSV not found: {args.input_csv}")
    args.output_dir.mkdir(parents=True, exist_ok=True)

    df = pd.read_csv(args.input_csv)
    validate_input(df)
    paired = make_paired_table(df)
    if paired.empty:
        raise SystemExit("No paired central/greybox runs after filtering status == ok and return_code == 0.")

    for case_name, paired_case in iter_cases(paired):
        stats_df = compute_metric_stats(paired_case)
        out_stats = args.output_dir / f"ratio_12metrics_{case_name}_stats.csv"
        out_png = args.output_dir / f"ratio_12metrics_{case_name}.png"
        stats_df.to_csv(out_stats, index=False)
        plot_case(stats_df, out_png)
        log_incomplete_cases(case_name, stats_df, expected_n=10)
        print(f"[{case_name}] saved plot={out_png.name} stats={out_stats.name}")


if __name__ == "__main__":
    main()
